use std::fs::File;
use std::io::{self, Read};
use serde_json::{Value, Error};

struct ConfigNode {
    data: Option<Value>,
    comments: Vec<String>,
}

impl From<ConfigNode> for String {
    fn from(node: ConfigNode) -> Self {
        let mut result = String::from("{");
        if let Some(val) = node.data { 
            result.push_str(&serde_json::to_string(&val).unwrap());
        }
        result.push_str(", \"");
        result.push_str(&node.comments.join("\", "));
        result.push_str("}");
        result.to_string()
    }
}

fn parse_json5_with_comments(file_path: &str) -> io::Result<Vec<String>> {
    let mut file = File::open(file_path)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?; 

    let raw_content = String::from_utf8(buffer).unwrap();

    let lines: Vec<String> = raw_content.lines().map(|s| s.trim().to_string()).collect();

    let mut nodes: Vec<ConfigNode> = Vec::new();
    let mut current_data: Option<Value> = None;
    let mut current_comments: Vec<String> = Vec::new();

    for line in lines { 
        if line.is_empty() || line.starts_with('#') { 
            nodes.push(ConfigNode { data: current_data, comments: current_comments.clone() });
            current_comments.clear();
            current_data = None;
        } else if line.contains(':') { 
            if let Ok(val) = serde_json::from_str::<Value>(&line) {
                nodes.push(ConfigNode { data: Some(val), comments: current_comments.clone() });
                current_data = None;
                current_comments.clear();
            }
        } else { 
            if let Ok(val) = serde_json::from_str::<Value>(&line) {
                nodes.push(ConfigNode { data: Some(val), comments: current_comments.clone() });
                current_data = None;
                current_comments.clear();
            }
        }
    }
    nodes.push(ConfigNode { data: current_data, comments: current_comments });

    Ok(nodes.into_iter().map(|node| node.into()).collect())
}

fn main() -> io::Result<()> {
    let test_file = "config.json5";
    std::fs::write(test_file, "# Start of confign{\"key\": \"value\" # This is a commentn// Another comment linen\"next_key\": 123}")?;

    match parse_json5_with_comments(test_file) {
        Ok(results) => {
            for (i, result) in results.iter().enumerate() {
                println!("Processed block {}: {}", i + 1, result);
            }
        },
        Err(e) => eprintln!("Error processing file: {}", e),
    }

    std::fs::remove_file(test_file)?; 
    Ok(())
}

use std::time::Duration;
use tokio::time::sleep;

struct PricingPathResult {
    path_id: usize,
    final_value: f64,
}

async fn calculate_single_path(path_id: usize) -> PricingPathResult {
    println!("Starting execution for path {}", path_id);
    sleep(Duration::from_millis((100 + (path_id % 3) * 50) as u64)).await;

    let final_value = 100.0 * (1.0 + (path_id as f64) / 100.0);

    println!("Finished execution for path {}", path_id);
    PricingPathResult {
        path_id,
        final_value,
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let num_paths = 5;
    let mut handles = vec![];

    for i in 0..num_paths {
        let handle = tokio::spawn(calculate_single_path(i));
        handles.push(handle);
    }

    let results: Vec<PricingPathResult> = futures::future::join_all(handles)
        .await
        .into_iter()
        .map(|result| result.expect("Task failed to execute"))
        .collect();

    println!("n--- Aggregated Results ---n");
    for result in results {
        println!("Path ID: {}, Final Value: {:.2}", result.path_id, result.final_value);
    }

    Ok(())
}

use std::sync::atomic::{AtomicUsize, Ordering};
use std::error::Error;
use std::sync::Arc;

struct SharedCounter {
    value: AtomicUsize,
}
impl SharedCounter {
    fn new() -> Self {
        SharedCounter { value: AtomicUsize::new(0) }
    }
    fn increment(&self) -> usize {
        self.value.fetch_add(1, Ordering::SeqCst) + 1
    }
}

async fn simulate_task(counter: Arc<SharedCounter>, delay_ms: usize) -> usize {
    let result = counter.increment();
    tokio::time::sleep(tokio::time::Duration::from_millis(delay_ms as u64)).await;
    result
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let counter = Arc::new(SharedCounter::new());
    let mut handles = vec![];
    let num_tasks = 10;

    for i in 0..num_tasks {
        let counter_clone = Arc::clone(&counter);
        let delay = (i % 3) * 50 + 100;
        let handle = tokio::spawn(async move {
            simulate_task(Arc::clone(&counter_clone), delay).await
        });
        handles.push(handle);
    }

    let results: Vec<usize> = futures::future::join_all(handles).await.into_iter().map(|r| r.unwrap()).collect();
    println!("Successfully processed {} tasks.", results.len());
    println!("Last counter value: {}", counter.value.load(Ordering::SeqCst));

    Ok(())
}

use std::sync::atomic::{AtomicBool, Ordering};
use std::thread;
use tokio::runtime;

struct FirmwareBlock {
    id: u32,
    data_size: usize,
    is_processed: AtomicBool,
}
impl Drop for FirmwareBlock {
    fn drop(&mut self) {
        if !self.is_processed.load(Ordering::SeqCst) {
            println!("Resource cleanup initiated for Block ID: {}", self.id);
        }
    }
}

async fn process_block(block: FirmwareBlock, delay_ms: u64) -> Result<(), String> {
    println!("Starting processing for Block ID: {}", block.id);
    tokio::time::sleep(tokio::time::Duration::from_millis(delay_ms)).await;
    block.is_processed.store(true, Ordering::SeqCst);
    println!("Finished processing for Block ID: {}", block.id);
    Ok(())
}

#[tokio::main]
async fn main() {
    let mut blocks = vec![FirmwareBlock { id: 101, data_size: 4096, is_processed: AtomicBool::new(false) }, 
                        FirmwareBlock { id: 102, data_size: 8192, is_processed: AtomicBool::new(false) }];

    let mut handles = vec![];
    for block in blocks.into_iter() {
        let handle = thread::spawn(move || { 
            runtime::Builder::new_current_thread()
                .enable_all()
                .build()
                .unwrap()
                .block_on(process_block(block, 100))
        });
        handles.push(handle);
    }

    for handle in handles {
        let _ = handle.join();
    }

    println!("All tasks completed. Scope exit will trigger cleanup.");
}
